package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;

/**
 * Returns the sum of a list of integers using reverse accumulation starting from nth.
 * The input parameter is not used ("nu").
 */
public class FromNthAlgo implements IListAlgo {
	/**
	 * Returns zero always.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return 0;
	}

	/**
	 * Returns first plus the sum of the rest of the list, starting from the nth position.
	 */
	public Object nonEmptyCase(NEList host, Object... params) {
		int n;
		if (params[0] instanceof String) {
			n = Integer.parseInt((String) params[0]);
		} else {
			n = (Integer) params[0];
		}
		n--;
		if (n <= 0) {
			return (int) host.getFirst() + (int) host.getRest().execute(this, n);
		} else {
			return host.getRest().execute(this, n);
		}
	}

}

package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;

/**
 * Returns the boolean value if a param is in a list of integers using reverse accumulation.
 * The input parameter is not used ("nu").
 */
public class SearchRevAlgo implements IListAlgo {
	/**
	 * Returns false for empty list.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return false;
	}

	/**
	 * Returns true if the element is found in the list using reverse accumulation.
	 */
	public Object nonEmptyCase(NEList host, Object... param) {
		boolean restResult = (boolean) host.getRest().execute(this, param[0]);
		if (restResult) return true;
		int target = Integer.parseInt((String) param[0]);
		return (int) host.getFirst() == target;
	}

}

package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;


/**
 *  Returns the largest of a list of integers using forward accumulation.
 *  The input parameter is not used ("nu").
 * @author Son Nguyen and Charlie Lockyer
 *
 */
public class LargestFwdAlgo implements IListAlgo {

	@Override
	/**
	 * The base case value is Min_Value,
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return Integer.MIN_VALUE;
	}

	@Override
	/**
	 * Pass the first value to the rest of the list, using a helper visitor, to be accumulated.
	 */
	public Object nonEmptyCase(NEList host, Object... nu) {
		// Use first element as initial accumulator, pass to helper on rest
		return host.getRest().execute(helper, host.getFirst());
	}

	/**
	 * Helper visitor that accumulates the max value through the list.
	 */
	private IListAlgo helper = new IListAlgo() {
		@Override
		public Object emptyCase(MTList host, Object... accs) {
			return accs[0]; // Return accumulated max
		}

		@Override
		public Object nonEmptyCase(NEList host, Object... accs) {
			int acc = (int) accs[0];
			int first = (int) host.getFirst();
			return host.getRest().execute(this, Math.max(acc, first));
		}
	};

}

package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;

/**
 * Returns the sum of a list of integers using reverse accumulation.
 * The input parameter is not used ("nu").
 * @author Son Nguyen and Charlie Lockyer
 */
public class LargestRevAlgo implements IListAlgo {
	/**
	 * Returns Min_value always.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return Integer.MIN_VALUE;
	}

	/**
	 * Returns max between first and rest
	 */
	public Object nonEmptyCase(NEList host, Object... nu) {
		int restMax = (int) host.getRest().execute(this);
		return Math.max((int) host.getFirst(), restMax);
	}

}

package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;


/**
 *  Returns the sum of a list of integers using forward accumulation.
 *  The input parameter is not used ("nu").
 * @author Son Nguyen and Charlie Lockyer
 *
 */
public class LastFwdAlgo implements IListAlgo {

	@Override
	/**
	 * The base case value is null,
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return null;
	}

	@Override
	/**
	 * Pass the first value to the rest of the list, using a helper visitor, to be accumulated.
	 */
	public Object nonEmptyCase(NEList host, Object... nu) {
		// Use first element as initial accumulator, pass to helper on rest
		return host.getRest().execute(helper, host.getFirst());
	}

	/**
	 * Helper visitor that replaces the accumulator with each new element.
	 */
	private IListAlgo helper = new IListAlgo() {
		@Override
		public Object emptyCase(MTList host, Object... accs) {
			return accs[0]; // Return the last element seen
		}

		@Override
		public Object nonEmptyCase(NEList host, Object... accs) {
			// Replace accumulator with current element
			return host.getRest().execute(this, host.getFirst());
		}
	};

}

package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;


/**
 *  Return a boolean indicating whether or not a given element is in the list.
 *  The input parameter is not used ("nu").
 * @author Son Nguyen and Charlie Lockyer
 *
 */
public class ContainFwdAlgo implements IListAlgo {

	@Override
	/**
	 * The base case value is false.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return false;
	}

	@Override
	/**
	 * Pass the first value to the rest of the list, using a helper visitor, to be accumulated.
	 */
	public Object nonEmptyCase(NEList host, Object... params) {
		int target = Integer.parseInt((String) params[0]);
		// Check first element, then pass boolean accumulator to helper
		boolean found = (int) host.getFirst() == target;
		return host.getRest().execute(helper, found, target);
	}

	/**
	 * Helper visitor that accumulates containment check through the list.
	 */
	private IListAlgo helper = new IListAlgo() {
		@Override
		public Object emptyCase(MTList host, Object... accs) {
			return accs[0]; // Return the accumulated boolean
		}

		@Override
		public Object nonEmptyCase(NEList host, Object... accs) {
			boolean found = (boolean) accs[0];
			int target = (int) accs[1];
			found = found || ((int) host.getFirst() == target);
			return host.getRest().execute(this, found, target);
		}
	};

}

package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IList;
import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;

/**
 * Return a list with the smallest element from the list removed.
 * Do this with a single pass through the the list!
 * The input parameter is not used ("nu").
 * @author Son Nguyen and Charlie Lockyer
 */
public class RemoveSmallestRevAlgo implements IListAlgo {

	/**
	 * Helper visitor that returns Object[]{IList resultList, int min, IList originalList}
	 * for internal recursive use.
	 */
	private IListAlgo helper = new IListAlgo() {
		@Override
		public Object emptyCase(MTList host, Object... nu) {
			return new Object[]{MTList.Singleton, Integer.MAX_VALUE, MTList.Singleton};
		}

		@Override
		public Object nonEmptyCase(NEList host, Object... nu) {
			Object[] restResult = (Object[]) host.getRest().execute(this);
			IList restList = (IList) restResult[0];
			int restMin = (int) restResult[1];
			IList restOriginal = (IList) restResult[2];
			int first = (int) host.getFirst();

			if (first <= restMin) {
				// Current element is new minimum; skip it, restore original rest
				return new Object[]{restOriginal, first, new NEList(first, restOriginal)};
			} else {
				// Current element is not the minimum; prepend it to the result
				return new Object[]{new NEList(first, restList), restMin, new NEList(first, restOriginal)};
			}
		}
	};

	/**
	 * Returns MTList.Singleton for empty list.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return MTList.Singleton;
	}

	/**
	 * Returns the list with the smallest element removed (first occurrence).
	 */
	public Object nonEmptyCase(NEList host, Object... nu) {
		Object[] restResult = (Object[]) host.getRest().execute(helper);
		IList restList = (IList) restResult[0];
		int restMin = (int) restResult[1];
		IList restOriginal = (IList) restResult[2];
		int first = (int) host.getFirst();

		if (first <= restMin) {
			return restOriginal; // Skip current element (it's the smallest)
		} else {
			return new NEList(first, restList); // Prepend; rest has smallest removed
		}
	}

}

package hw06.model.BallHosts;

import java.awt.Color;
import java.awt.Component;
import java.awt.Point;

import hw06.model.BallVisitors.BallAlgo;
import hw06.model.BallVisitors.IBallAlgo;
import provided.ballworld.extVisitors.IBallHostID;
import provided.ballworld.extVisitors.impl.BallHostIDFactory;
import provided.extvisitor.IExtVisitor;

/**
 * A ball type whose instances can appear to dynamically change their type. 
 * This type change manifests itself as a change in the case invoked on its visitors.  
 * This class implements a local host ID value that overrides the inherited host ID value from ABall.
 * The overridden host ID value, not the inherited ID value, is used when executing visitors.<br/>
 * WARNING: Because this class does not add any methods or fields to ABall, 
 * there can be problems when attempting to mimic any ball that does so!   
 * Be VERY careful when using with visitors that treat the host as anything other than an IBall!   
 * @author swong
 *
 */
public class DynamicBall extends ABall {
	/**
	 * Add generated serialVerionUID
	 */
	private static final long serialVersionUID = 6115873538313721264L;

	/**
	 *  The identifying host ID for this class.  The overridden host ID defaults to this value.
	 *  This is NOT the value used when executing visitors!
	 */
	public static final IBallHostID ID = BallHostIDFactory.Singleton.makeID(DynamicBall.class.getName());

	/**
	 * The overridden host ID value used when executing visitors.
	 */
	private IBallHostID hostID = ID;

	/**
	 * Constructor for the class that defaults the overridden ID to be this class's ID and sets the 
	 * inherited host ID to be that same value.  This constructor would typically be used when this 
	 * class is being instantiated directly.
	 * @param radius the initial radius of this Ball.
	 * @param velocity the initial velocity of this Ball.
	 * @param color The initial color of the ball.
	 * @param location the initial center of this Ball.
	 * @param container the adapter to the system model
	 * @param configAlgo The algo to complete the installation of strategies and any other desired operations
	 */
	public DynamicBall(Point location, int radius, Point velocity, Color color, Component container,
			IBallAlgo<Void, Void> configAlgo) {
		this(ID, location, radius, velocity, color, container, configAlgo);
	}

	/**
	 * Constructor for the class that defaults the overridden ID and inherited ID to be the given initial ID value.
	 * This constructor would typically be used by a subclass to set the inherited ID and initial overridden ID values 
	 * to be the subclass's host ID value.
	 * @param initHostID The initial host ID value to use.
	 * @param radius the initial radius of this Ball.
	 * @param velocity the initial velocity of this Ball.
	 * @param color The initial color of the ball.
	 * @param location the initial center of this Ball.
	 * @param container the adapter to the system model
	 * @param configAlgo The algo to complete the installation of strategies and any other desired operations
	 */
	public DynamicBall(IBallHostID initHostID, Point location, int radius, Point velocity, Color color,
			Component container, IBallAlgo<Void, Void> configAlgo) {
		super(initHostID, location, radius, velocity, color, container, configAlgo);
		setHostID(initHostID);  
	}

	/**
	 * Change the apparent type of this ball to the given type.  <br/>
	 * WARNING: Do NOT change to a host type whose implementing class 
	 * adds methods and/or fields to ABall!
	 * @param hostID The new host ID value
	 */
	public void setHostID(IBallHostID hostID) {
		this.hostID = hostID;
	}

	/**
	 * {@inheritDoc}
	 * <br/>
	 * Uses the overridden host ID value held in this class instead of the inherited host ID value.
	 */
	@SuppressWarnings("unchecked")
	@Override
	public <R, P> R execute(IExtVisitor<R, IBallHostID, P, ? extends IBall> algo, P... params) {
		if (hostID == null) {
			// During super constructor, hostID field hasn't been initialized yet;
			// fall back to inherited behavior using the ID passed to ABallHost
			return super.execute(algo, params);
		}
		return (R) ((IExtVisitor) algo).caseAt(hostID, this, params);
	}
}

package hw06.model.BallVisitors;

import java.util.function.Function;

import hw06.model.BallHosts.IBall;
import provided.ballworld.extVisitors.IBallHostID;
import provided.ballworld.extVisitors.impl.BallHostIDFactory;

/**
 * A ball algo that is designed to process either a single type of ball or all ball types 
 * using a function provided as the input parameter.
 * Input parameter:   Function<IBall, R> a function that takes the ball host and returns a value of type R.  Executing the visitor will 
 * return either the return value from this function or the return value of the default case command, e.g. null if 
 * the default case cmd is a no-op. 
 * This function is run for the currently set processed ball type or the default case, if set.
 * To set the default case as the processed ball type, use this instance's getDefaultType() value as the identifier
 * for the default case. 
 * 
IMPORTANT: Any commands added using setCmd() or removed using removeCmd() are NOT controlled by the methods of this 
 * subclass and are not affected by the methods in this subclass unless that specific ball type was affected by the setType() method!  
 * @author swong
 *
 * @param <R>   The return type of the input parameter function.
 */
public class OneTypeBallAlgo<R> extends BallAlgo<R, Function<IBall, R>> {

	/**
	 * Add generated serialVersionUID
	 */
	private static final long serialVersionUID = -3137191847691308721L;

	/**
	 * The no-op command used by this algo.
	 */
	private ABallAlgoCmd<R, Function<IBall, R>> defaultCmd = ABallAlgoCmd.MakeNull();

	/**
	 * The command that runs the given function
	 */
	private ABallAlgoCmd<R, Function<IBall, R>> runFuncCmd = new ABallAlgoCmd<>() {
		/**
		 * Add generated serialVersionUID
		 */
		private static final long serialVersionUID = 1L;

		@Override
		public R apply(IBallHostID index, IBall host, @SuppressWarnings("unchecked") Function<IBall, R>... fns) {
			return fns[0].apply(host);
		}

	};

	/**
	 * The IBallHostID that is used to uniquely identify the default case in the algo. 
	 */
	private IBallHostID defaultID = BallHostIDFactory.Singleton.makeID(OneTypeBallAlgo.class.getName());

	/**
	 * The ball type that is currently being processed.
	 */
	private IBallHostID currentID = defaultID;

	/**
	 * Constructor for the class where the default case is a no-op if it is not the processed ball type.
	 * @param defaultTypeName The friendly name given to the IBallHostID this instance uses to identify its default case.
	 * @param isDefaultRunFunc If true, then the default case will be set to running the given function.  
	 * Otherwise the default case will be a no-op.
	 */
	public OneTypeBallAlgo(String defaultTypeName, boolean isDefaultRunFunc) {
		this(defaultTypeName, isDefaultRunFunc, ABallAlgoCmd.MakeNull());
	}

	/**
	 * Constructor for the class where the default case is the given defaultCmd if it is not the processed ball type.
	 * @param defaultTypeName The friendly name given to the IBallHostID this instance uses to identify its default case.
	 * @param isDefaultRunFunc If true, then the default case will be set to running the given function.  
	 * Otherwise the default case will be the given defaultCmd.
	 * @param defaultCmd The command to use for the default case if it is not the processed type.
	 */
	public OneTypeBallAlgo(String defaultTypeName, boolean isDefaultRunFunc, ABallAlgoCmd<R, Function<IBall, R>> defaultCmd) {
		super(defaultCmd);
		this.defaultID = BallHostIDFactory.Singleton.makeID(defaultTypeName);  // Generate the special ID for default case
		this.defaultCmd = defaultCmd; // Save the default cmd so the default case can be reset later
		reset(isDefaultRunFunc); // Initialize to a reset state
	}

	/**
	 * Gets the IBallHostID this instance uses to identify its default case.
	 * This value is instance-dependent!
	 * @return This instance's default case identifier ID.
	 */
	public IBallHostID getDefaultType() {
		return this.defaultID;
	}

	/**
	 * Resets the algorithm such the current ball ID being used is for processing is the default ID, i.e. the default command.
	 * The default case processing depends on the value of isDefaultRunFunc.  If isDefaultRunFunc = false, then the default case cmd 
	 * set by the constructor will be used.  If isDefaultRunFunc = true, then the default case will process all ball types with the given 
	 * input parameter function, returning the function's return value.
	 * reset(false) can be used to disable this algo if the default case cmd is a no-op.
	 * @param isDefaultRunFunc If true, the default case is set to run the given input parameter function of the algo.  
	 * Otherwise, the default case cmd is used.
	 */
	public void reset(boolean isDefaultRunFunc) {
		// Clean up previous specific type if it was not the default
		if (!currentID.equals(defaultID)) {
			removeCmd(currentID);
		}
		// Reset to default ID
		currentID = defaultID;
		// Set default case behavior
		if (isDefaultRunFunc) {
			setDefaultCmd(runFuncCmd);
		} else {
			setDefaultCmd(defaultCmd);
		}
	}

	/**
	 * Gets the current processing state of the algo's default case.
	 * @return true, if the default case is set to run the given input parameter function of the algo.
	 * Otherwise, the default case is a no-op.
	 */
	public boolean isDefaultRunFunc() {
		return getDefaultCmd() == runFuncCmd;
	}

	/**
	 * Gets the current ball type that is being processed. 
	 * If the default ID is returned, then all ball types are being processed.
	 * Note: if reset(false) was called, the default case is set to be a no-op and no other ball types are being explicitly processed.
	 * The default ID value is returned in that scenario.
	 * @return The current ball type being processed.
	 */
	public IBallHostID getCurrentType() {
		return currentID;
	}

	/**
	 * Changes the current ball type to be processed to the given type.
	 * If the default case is desired, then use getDefaultType() as the ballTypeID value.
	 * The previous ball type will be configured to run the default case,
	 * i.e the command associated with that type is removed if it is not the default case.
	 * If the previous type was the default case, the default case will be set to be a no-op, 
	 * unless the default case is indicated by ballTypeID.
	 * @param ballTypeID The type of the ball to be set for processing.
	 */
	public void setType(IBallHostID ballTypeID) {
		// Clean up previous type
		if (currentID.equals(defaultID)) {
			// Previous was default case; set to no-op unless new type is also default
			if (!ballTypeID.equals(defaultID)) {
				setDefaultCmd(defaultCmd);
			}
		} else {
			// Previous was a specific type; remove its command
			removeCmd(currentID);
		}

		// Set up new type
		currentID = ballTypeID;
		if (ballTypeID.equals(defaultID)) {
			// Process all types via default case
			setDefaultCmd(runFuncCmd);
		} else {
			// Process only the specific type
			setCmd(ballTypeID, runFuncCmd);
		}
	}
}

package hw06.model.BallVisitors;

import hw06.model.BallHosts.IBall;
import provided.ballworld.extVisitors.IBallHostID;

/**
 * Algorithm that will return true if the host is the same type as the given input parameter.
 * This algorithm will always work, even for dynamically typed balls.
 * Parameter: An IBall instance.
 * Returns:  True if the host and the parameter are the same type.  False otherwise.
 * Usage:  boolean result = host.execute(SameTypeBallAlgo.Singleton, other) 
 * @author swong
 *
 */
public class SameTypeBallAlgo extends BallAlgo<Boolean, IBall> {
	/**
	 *  Add generated serialVersionUID
	 */
	private static final long serialVersionUID = 8380154111346265229L;
	/**
	 * Singleton instance
	 */
	public static final SameTypeBallAlgo Singleton = new SameTypeBallAlgo();

	/**
	 * Private constructor for the class.  
	 */
	private SameTypeBallAlgo() {
		// TODO: Implement this constructor
		// Only a default case is needed here because the main purpose here is to get the current ID value of the host
		// and to create a second visitor algorithm based on that ID value.
		super(new ABallAlgoCmd<>() {
			/**
			 * Add generated serialVersionUID
			 */
			private static final long serialVersionUID = 8451834955902576424L;

			@Override
			public Boolean apply(IBallHostID hostID, IBall host, IBall... otherBalls) {
				// Create a visitor that returns true only for the same host ID as this host
				BallAlgo<Boolean, IBall> matchAlgo = new BallAlgo<>(new ABallAlgoCmd<Boolean, IBall>() {
					private static final long serialVersionUID = 1L;

					@Override
					public Boolean apply(IBallHostID index, IBall h, IBall... params) {
						return false; // Default: different type
					}
				});
				// Add a specific case for the host's type that returns true
				matchAlgo.setCmd(hostID, new ABallAlgoCmd<Boolean, IBall>() {
					private static final long serialVersionUID = 1L;

					@Override
					public Boolean apply(IBallHostID index, IBall h, IBall... params) {
						return true; // Same type
					}
				});
				// Execute the match algo on the other ball
				return otherBalls[0].execute(matchAlgo);
			}
		});
	}
}

package hw05.model.updateStrategies;

import provided.utils.dispatcher.IDispatcher;
import hw05.model.IBall;
import hw05.model.IBallCmd;

/**
 * An update strategy that combines two strategies into a strategy with both behaviors
 */
public class MultiStrategy implements IUpdateStrategy {

	/**
	 * The update strategy containing the first behavior
	 */
	private IUpdateStrategy firstStrategy;

	/**
	 * The update strategy containing the second behavior
	 */
	private IUpdateStrategy secondStrategy;

	/**
	 * Instantiates a MultiStrategy given two update strategies to combine
	 * @param firstStrategy the update strategy containing the first behavior
	 * @param secondStrategy the update strategy containing the second behavior
	 */
	public MultiStrategy(IUpdateStrategy firstStrategy, IUpdateStrategy secondStrategy) {
		this.firstStrategy = firstStrategy;
		this.secondStrategy = secondStrategy;
	}

	@Override
	/**
	 * Method to update state of ball based on MultiStrategy
	 * @param context the ball whose state is being updated
	 * @param disp the dispatcher that is observing the ball
	 */
	public void updateState(IBall context, IDispatcher<IBallCmd> disp) {
		firstStrategy.updateState(context, disp);
		secondStrategy.updateState(context, disp);
	}

	@Override
	public void init(IBall context) {

	}


}

package hw05.model.updateStrategies;

import java.awt.Point;

import provided.utils.dispatcher.IDispatcher;
import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.displayModel.IDimension;

/**
 * An energy strategy is a strategy by which the ball gains speed by a factor of 50% 
 * when contacting the top and left boundaries of the GUI panel but loses speed 
 * by a factor of ~33% when contacting the bottom and right boundaries of the GUI panel.
 * @author akashkaranam
 */
public class EnergyStrategy implements IUpdateStrategy {

	/**
	 * float that determines how much speed increases on contact with left and top boundaries
	 */
	private float powerUp = 1.5f;
	/**
	 * float that determines how much speed decreases on contact with right and bottom boundaries
	 */
	private float powerDown = .66f;

	/**
	 * Method to change the speed of the ball based on contact with boundaries
	 * @param disp the dispatcher that makes calls to update the balls
	 */
	@Override
	public void updateState(IBall context, IDispatcher<IBallCmd> disp) {
		IDimension dim = context.getDimension();
		Point loc = context.getLocation();
		Point vel = context.getVelocity();
		int r = context.getRadius();

		if (loc.x - r <= 0 || loc.y - r <= 0) {
			context.setVelocity(new Point(Math.round(vel.x * powerUp), Math.round(vel.y * powerUp)));
		}
		if (loc.x + r >= dim.getWidth() || loc.y + r >= dim.getHeight()) {
			context.setVelocity(new Point(Math.round(vel.x * powerDown), Math.round(vel.y * powerDown)));
		}
	}

	@Override
	public void init(IBall context) {

	}


}

package hw05.model.updateStrategies;

import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * A criteria that allows balls with the same paint strategy to interact
 * @author charlielockyer
 *
 */
public class SamePaintCriteriaStrategy implements IUpdateStrategy{


	public void updateState(final IBall source, IDispatcher<IBallCmd> dispatcher) {
		dispatcher.updateAll(new IBallCmd() {
			@Override
			public void apply(IBall other, IDispatcher<IBallCmd> disp) {
				if (other != source) {
					if (source.getPaintStrategy().getClass().equals(other.getPaintStrategy().getClass())) {
						IBallCmd cmd = source.interactWithThen(other, disp);
						cmd.apply(source, disp);
					}
