						host.setUpdateStrategy(context.getUpdateStrategy());
						host.setPaintStrategy(context.getPaintStrategy());
						host.setInteractStrategy(context.getInteractStrategy());
					}
				}
			);
			dispatcher.addObserver(newBall);
		}
	}

